import React, { useEffect } from "react";
import { useKakaomap } from "./useKakaomap";
import './Kakao.css';
import Detail from './Detail'; // Detail 컴포넌트를 import

function Kakao() {
  const [isDetailOpen, setIsDetailOpen] = React.useState(false); // Detail 컴포넌트가 열려 있는지 여부를 상태로 관리

  const handleCloseDetail = React.useCallback(() => {
    setIsDetailOpen(false);
  }, []);

  const mapscript = useKakaomap(onCloseDetail); // onCloseDetail 함수를 useKakaomap 훅에 전달

  useEffect(() => {
    const script = document.createElement("script");
    script.src = `//dapi.kakao.com/v2/maps/sdk.js?appkey=${process.env.REACT_APP_KAKAOMAP_API_KEY}&libraries=services,drawing`;
    script.async = true;
    script.onload = () => {
      mapscript();
    };
    script.onerror = (error) => {
      console.error("Error loading Kakao maps script:", error);
    };
    document.body.appendChild(script);

    return () => {
      document.body.removeChild(script);
    };
  }, [mapscript]);

  return (
    <div>
      <div id="map" style={{ width: "100%", height: "100vh" }}></div>
      {isDetailOpen && <Detail item={item} onClose={handleCloseDetail} />} {/* Detail 컴포넌트를 렌더링 */}
    </div>
  );
}

export default Kakao;
